private enum ClaudeScreenFactory {
    @ViewBuilder
    static func screen(for tab: String) -> some View {
        switch tab.lowercased() {
        case let t where t.contains("chat") || t.contains("discover") || t.contains("histor"):
            ClaudeChatScreen()
        default:
            ClaudeGenericListScreen(title: tab)
        }
    }
}
