private struct ClaudeChatScreen: View {
    @State private var draft = ""
    var body: some View {
        VStack(spacing: 0) {
            ScrollView {
                VStack(spacing: 12) {
                    ForEach(ClaudeDemoData.messages) { msg in
                        if msg.isUser { ClaudeUserBubble(text: msg.text, accent: ClaudeTokens.claudeCream) }
                        else { ClaudeAssistantBubble(text: msg.text, surface: ClaudeTokens.claudeSurface1) }
                    }
                }.padding()
            }.background(ClaudeTokens.claudeDarkCanvas.ignoresSafeArea())
            HStack(spacing: 12) {
                TextField("Message Claude…", text: $draft, axis: .vertical).padding(10).background(RoundedRectangle(cornerRadius: 20).fill(ClaudeTokens.claudeSurface1))
                Button {} label: { Image(systemName: "arrow.up.circle.fill").font(.title2).foregroundStyle(ClaudeTokens.claudeCream) }
            }.padding().background(.bar)
        }
    }
}

private struct ClaudeUserBubble: View {
    let text: String; let accent: Color
    var body: some View { HStack { Spacer(minLength: 48); Text(text).padding(12).background(RoundedRectangle(cornerRadius: 16).fill(accent.opacity(0.15))) } }
}

private struct ClaudeAssistantBubble: View {
    let text: String; let surface: Color
    var body: some View { HStack { Text(text).padding(12).background(RoundedRectangle(cornerRadius: 16).fill(surface)); Spacer(minLength: 48) } }
}

